class Solution {
public:
    int calculate(string s) {
        int n = s.size();
        long long currNum = 0;
        char operation = '+';
        stack<long long> st;

        for (int i = 0; i < n; i++) {
            if (isdigit(s[i])) {
                currNum = currNum * 10 + (s[i] - '0');
            }

            if ((!isdigit(s[i]) && !isspace(s[i])) || i == n - 1) {
                if (operation == '+') {
                    st.push(currNum);
                } else if (operation == '-') {
                    st.push(-currNum);
                } else if (operation == '*') {
                    long long last = st.top();
                    st.pop();
                    st.push(last * currNum);
                } else {
                    long long last = st.top();
                    st.pop();
                    st.push(last / currNum);
                }

                operation = s[i];
                currNum = 0;
            }
        }

        int res = 0;
        while (!st.empty()) {
            res += st.top();
            st.pop();
        }

        return res;
    }
};
```
